//! parity-wire-roundtrip — f32 encoding fidelity test.
//!
//! Tests the byte-encoding functions used by fat-station.rs (f32_to_body / body_to_f32)
//! AND does a live HTTP roundtrip against a running fat-station to verify no
//! bytes are lost or reordered in the wire path.
//!
//! Usage:
//!   cargo run --release --bin parity-wire-roundtrip -- /tmp/qwen-coder-7b.knot [station_url]
//!
//! If station_url is provided (e.g. http://127.0.0.1:8001), the binary also
//! does a live /embed roundtrip and compares.

use std::env;
use std::time::Instant;

use distributed_inference::loader::KnotWeights;
use distributed_inference::NativeLlamaPipeline;

fn f32_to_body(arr: &[f32]) -> Vec<u8> {
    let mut out = Vec::with_capacity(arr.len() * 4);
    for v in arr {
        out.extend_from_slice(&v.to_bits().to_le_bytes());
    }
    out
}

fn body_to_f32(body: &[u8]) -> Vec<f32> {
    assert!(body.len().is_multiple_of(4));
    let n = body.len() / 4;
    let mut out = vec![0.0f32; n];
    for i in 0..n {
        let off = i * 4;
        let word = u32::from_le_bytes([body[off], body[off + 1], body[off + 2], body[off + 3]]);
        out[i] = f32::from_bits(word);
    }
    out
}

fn u32_to_body(arr: &[u32]) -> Vec<u8> {
    let mut out = Vec::with_capacity(arr.len() * 4);
    for v in arr {
        out.extend_from_slice(&v.to_le_bytes());
    }
    out
}

fn cosine(a: &[f32], b: &[f32]) -> f32 {
    let n = a.len().min(b.len());
    let (mut dot, mut na, mut nb) = (0.0f64, 0.0f64, 0.0f64);
    for i in 0..n {
        let (av, bv) = (a[i] as f64, b[i] as f64);
        dot += av * bv;
        na += av * av;
        nb += bv * bv;
    }
    let d = na.sqrt() * nb.sqrt();
    if d == 0.0 {
        0.0
    } else {
        (dot / d) as f32
    }
}

fn max_abs_delta(a: &[f32], b: &[f32]) -> f32 {
    let n = a.len().min(b.len());
    let mut m = 0.0f32;
    for i in 0..n {
        let d = (a[i] - b[i]).abs();
        if d > m {
            m = d;
        }
    }
    m
}

fn main() -> Result<(), String> {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        return Err("usage: parity-wire-roundtrip <knot> [station_url]".into());
    }
    let knot_path = args[1].clone();
    let station_url = args.get(2).cloned();

    println!("============================================================");
    println!(" parity-wire-roundtrip");
    println!("   knot: {}", knot_path);
    if let Some(ref url) = station_url {
        println!("   station: {}", url);
    }
    println!("============================================================");

    let knot = KnotWeights::load(&knot_path)?;
    let cfg = knot.config.as_ref().ok_or("no config block")?;
    let hidden_dim = cfg.hidden_dim;
    println!("[meta] hidden={}", hidden_dim);

    let mut p = NativeLlamaPipeline::from_knot(knot, false, 0.0);

    // ── TEST 1: f32_to_body / body_to_f32 roundtrip ──
    println!("\n--- TEST 1: f32 encoding roundtrip ---");
    let tokens: Vec<u32> = vec![151644, 8948, 198, 9707];
    let embed = p.embed_chunk(&tokens, 0)?;
    println!(
        "  embed: {} floats, first4=[{:.6}, {:.6}, {:.6}, {:.6}]",
        embed.len(),
        embed[0],
        embed[1],
        embed[2],
        embed[3]
    );

    let encoded = f32_to_body(&embed);
    println!("  encoded: {} bytes", encoded.len());
    println!("  first 16 bytes: {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x}",
             encoded[0], encoded[1], encoded[2], encoded[3],
             encoded[4], encoded[5], encoded[6], encoded[7],
             encoded[8], encoded[9], encoded[10], encoded[11],
             encoded[12], encoded[13], encoded[14], encoded[15]);

    let decoded = body_to_f32(&encoded);
    let cos1 = cosine(&embed, &decoded);
    let mxa1 = max_abs_delta(&embed, &decoded);
    println!("  decoded: {} floats", decoded.len());
    println!("  cosine={:.10} max-abs={:.10}", cos1, mxa1);

    let mut byte_diff = 0usize;
    for i in 0..embed.len() {
        if embed[i].to_bits() != decoded[i].to_bits() {
            byte_diff += 1;
        }
    }
    println!("  bit-exact mismatches: {}", byte_diff);
    let pass1 = byte_diff == 0;
    println!("  TEST 1: {}", if pass1 { "PASS" } else { "FAIL" });

    // ── TEST 2: special float values ──
    println!("\n--- TEST 2: special float values ---");
    let special: Vec<f32> = vec![
        0.0,
        -0.0,
        f32::INFINITY,
        f32::NEG_INFINITY,
        f32::NAN,
        f32::MIN,
        f32::MAX,
        f32::EPSILON,
        1e-38,
        -1e-38,
        std::f32::consts::PI,
        -std::f32::consts::E,
    ];
    let enc2 = f32_to_body(&special);
    let dec2 = body_to_f32(&enc2);
    let mut pass2 = true;
    for i in 0..special.len() {
        let orig = special[i].to_bits();
        let rtrip = dec2[i].to_bits();
        if orig != rtrip {
            println!(
                "  MISMATCH at [{}]: orig={:08x} rtrip={:08x}",
                i, orig, rtrip
            );
            pass2 = false;
        }
    }
    println!("  TEST 2: {}", if pass2 { "PASS" } else { "FAIL" });

    // ── TEST 3: live HTTP roundtrip (if station URL provided) ──
    let mut pass3 = true;
    if let Some(ref url) = station_url {
        println!("\n--- TEST 3: live HTTP roundtrip to {} ---", url);

        // First check /health
        let health_url = format!("{}/health", url);
        match ureq::get(&health_url).call() {
            Ok(resp) => {
                let body = resp.into_string().unwrap_or_default();
                println!("  /health: {}", body);
            }
            Err(e) => {
                println!("  /health FAILED: {} — station may be down", e);
                pass3 = false;
            }
        }

        if pass3 {
            // Do /embed with the same tokens and compare the returned residual
            // against the locally-computed one.
            let embed_url = format!("{}/embed", url);
            let token_bytes = u32_to_body(&tokens);
            println!(
                "  POST /embed: {} tokens ({} bytes)",
                tokens.len(),
                token_bytes.len()
            );
            println!("  first 16 body bytes: {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x}",
                     token_bytes[0], token_bytes[1], token_bytes[2], token_bytes[3],
                     token_bytes[4], token_bytes[5], token_bytes[6], token_bytes[7],
                     token_bytes[8], token_bytes[9], token_bytes[10], token_bytes[11],
                     token_bytes[12], token_bytes[13], token_bytes[14], token_bytes[15]);

            let t = Instant::now();
            match ureq::post(&embed_url)
                .set("Content-Type", "application/octet-stream")
                .set("X-Position", "0")
                .set("X-Token-Count", &tokens.len().to_string())
                .set("X-Request-Id", "parity-wire-roundtrip")
                .send_bytes(&token_bytes)
            {
                Ok(resp) => {
                    let status = resp.status();
                    let mut body_bytes = Vec::new();
                    resp.into_reader().read_to_end(&mut body_bytes).unwrap_or(0);
                    println!(
                        "  response: HTTP {} {} bytes in {} ms",
                        status,
                        body_bytes.len(),
                        t.elapsed().as_millis()
                    );

                    if body_bytes.len() % 4 != 0 {
                        println!(
                            "  !! response body length {} not multiple of 4",
                            body_bytes.len()
                        );
                        pass3 = false;
                    } else {
                        let remote_embed = body_to_f32(&body_bytes);
                        println!(
                            "  remote: {} floats, first4=[{:.6}, {:.6}, {:.6}, {:.6}]",
                            remote_embed.len(),
                            remote_embed.first().unwrap_or(&0.0),
                            remote_embed.get(1).unwrap_or(&0.0),
                            remote_embed.get(2).unwrap_or(&0.0),
                            remote_embed.get(3).unwrap_or(&0.0)
                        );
                        println!(
                            "  local:  {} floats, first4=[{:.6}, {:.6}, {:.6}, {:.6}]",
                            embed.len(),
                            embed[0],
                            embed[1],
                            embed[2],
                            embed[3]
                        );

                        if remote_embed.len() != embed.len() {
                            println!(
                                "  !! LENGTH MISMATCH: remote={} local={}",
                                remote_embed.len(),
                                embed.len()
                            );
                            pass3 = false;
                        } else {
                            let cos3 = cosine(&embed, &remote_embed);
                            let mxa3 = max_abs_delta(&embed, &remote_embed);
                            println!("  cosine={:.10} max-abs={:.10}", cos3, mxa3);

                            // Hex-dump first 16 bytes of each for visual comparison
                            let local_bytes = f32_to_body(&embed);
                            println!("  local  first16: {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x}",
                                     local_bytes[0], local_bytes[1], local_bytes[2], local_bytes[3],
                                     local_bytes[4], local_bytes[5], local_bytes[6], local_bytes[7],
                                     local_bytes[8], local_bytes[9], local_bytes[10], local_bytes[11],
                                     local_bytes[12], local_bytes[13], local_bytes[14], local_bytes[15]);
                            println!("  remote first16: {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x}",
                                     body_bytes[0], body_bytes[1], body_bytes[2], body_bytes[3],
                                     body_bytes[4], body_bytes[5], body_bytes[6], body_bytes[7],
                                     body_bytes[8], body_bytes[9], body_bytes[10], body_bytes[11],
                                     body_bytes[12], body_bytes[13], body_bytes[14], body_bytes[15]);

                            pass3 = mxa3 == 0.0;
                        }
                    }
                }
                Err(e) => {
                    println!("  /embed FAILED: {}", e);
                    pass3 = false;
                }
            }
        }
        println!("  TEST 3: {}", if pass3 { "PASS" } else { "FAIL" });
    }

    // Summary
    println!("\n============================================================");
    let all_pass = pass1 && pass2 && pass3;
    println!(" SUMMARY");
    println!(
        "   T1 (f32 roundtrip)    : {}",
        if pass1 { "PASS" } else { "FAIL" }
    );
    println!(
        "   T2 (special values)   : {}",
        if pass2 { "PASS" } else { "FAIL" }
    );
    if station_url.is_some() {
        println!(
            "   T3 (HTTP roundtrip)   : {}",
            if pass3 { "PASS" } else { "FAIL" }
        );
    }
    println!(
        "   verdict               : {}",
        if all_pass { "PASS" } else { "FAIL" }
    );
    println!("============================================================");

    if !all_pass {
        std::process::exit(2);
    }
    Ok(())
}
